"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[9643],{98974(e,a,o){o.r(a),o.d(a,{assets:()=>t,contentTitle:()=>m,default:()=>u,frontMatter:()=>n,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/applications-of-qc","title":"Para quais problemas os computadores qu\xe2nticos s\xe3o bons?","description":"Leia sobre como decidimos os tipos de problemas que podem se beneficiar de uma solu\xe7\xe3o qu\xe2ntica, e veja alguns exemplos recentes de trabalhos da comunidade.","source":"@site/i18n/pt/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/applications-of-qc.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/applications-of-qc","permalink":"/learning/courses/quantum-computing-in-practice/applications-of-qc","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/applications-of-qc.mdx","tags":[],"version":"current","frontMatter":{"title":"Para quais problemas os computadores qu\xe2nticos s\xe3o bons?","sidebar_label":"Para quais problemas os computadores qu\xe2nticos s\xe3o bons?","description":"Leia sobre como decidimos os tipos de problemas que podem se beneficiar de uma solu\xe7\xe3o qu\xe2ntica, e veja alguns exemplos recentes de trabalhos da comunidade.","notebook_path":"learning/courses/quantum-computing-in-practice/applications-of-qc.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"QAOA em escala de utilidade","permalink":"/learning/courses/quantum-computing-in-practice/utility-scale-qaoa"},"next":{"title":"Mapeamento","permalink":"/learning/courses/quantum-computing-in-practice/mapping"}}');var i=o(74848),r=o(28453);const n={title:"Para quais problemas os computadores qu\xe2nticos s\xe3o bons?",sidebar_label:"Para quais problemas os computadores qu\xe2nticos s\xe3o bons?",description:"Leia sobre como decidimos os tipos de problemas que podem se beneficiar de uma solu\xe7\xe3o qu\xe2ntica, e veja alguns exemplos recentes de trabalhos da comunidade.",notebook_path:"learning/courses/quantum-computing-in-practice/applications-of-qc.ipynb"},m=void 0,t={},d=[{value:"Introdu\xe7\xe3o",id:"introduction",level:2},{value:"Dificuldade cl\xe1ssica vs. qu\xe2ntica",id:"classical-vs-quantum-difficulty",level:2},{value:"Classes de complexidade",id:"complexity-classes",level:3},{value:"Os computadores qu\xe2nticos de hoje e seus limites",id:"todays-quantum-computers-and-their-limits",level:3},{value:"\xc1reas de aplica\xe7\xe3o e casos de uso",id:"application-areas-and-use-cases",level:2},{value:"Caso de Uso 1: Simulando a din\xe2mica de h\xe1drons",id:"use-case-1-simulating-hadron-dynamics",level:3},{value:"Caso de Uso 2: Otimiza\xe7\xe3o de um vidro de spin de Ising",id:"use-case-2-optimization-of-an-ising-spin-glass",level:3},{value:"Caso de Uso 3: Previs\xe3o de estrutura secund\xe1ria de mRNA",id:"use-case-3-mrna-secondary-structure-prediction",level:3},{value:"Conclus\xe3o",id:"conclusion",level:2}];function c(e){const a={a:"a",annotation:"annotation",h2:"h2",h3:"h3",img:"img",li:"li",math:"math",mi:"mi",mn:"mn",mo:"mo",mrow:"mrow",ol:"ol",p:"p",semantics:"semantics",span:"span",ul:"ul",...(0,r.R)(),...e.components},{IBMVideo:s}=a;return s||function(e,a){throw new Error("Expected "+(a?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,i.jsxs)(i.Fragment,{children:["\n","\n",(0,i.jsxs)(a.p,{children:["Assista ao v\xeddeo sobre aplica\xe7\xf5es da computa\xe7\xe3o qu\xe2ntica por Olivia Lanes, ou abra o v\xeddeo em uma janela separada no ",(0,i.jsx)(a.a,{href:"https://youtu.be/33QmsXhIlpU",children:"YouTube."})]}),"\n",(0,i.jsx)(s,{id:"134063426",title:"In this video, Olivia Lanes describes several possible applications of quantum computing at the utility scale. These include simulating hadrons and spin glasses, as well as modeling protein structure."}),"\n",(0,i.jsx)(a.h2,{id:"introduction",children:"Introdu\xe7\xe3o"}),"\n",(0,i.jsx)(a.p,{children:"Na aula anterior, abordamos um \xfanico problema em profundidade \u2014 resolver o problema de otimiza\xe7\xe3o Max-Cut usando a formula\xe7\xe3o QUBO. Hoje vamos adotar uma abordagem diferente e discutir aplica\xe7\xf5es de curto prazo de forma mais ampla. Come\xe7aremos dando a voc\xea uma ideia de como decidimos quais tipos de problemas podem se beneficiar de uma solu\xe7\xe3o qu\xe2ntica. Em seguida, veremos alguns exemplos recentes de trabalhos realizados em nossa comunidade. Isso vai ajud\xe1-lo a desenvolver uma intui\xe7\xe3o para diferentes tipos de problemas de computa\xe7\xe3o qu\xe2ntica e como os abordamos."}),"\n",(0,i.jsx)(a.h2,{id:"classical-vs-quantum-difficulty",children:"Dificuldade cl\xe1ssica vs. qu\xe2ntica"}),"\n",(0,i.jsx)(a.p,{children:"Antes de mergulhar nos exemplos, vamos primeiro discutir como estudamos e categorizamos a dificuldade de v\xe1rios problemas. Alguns problemas podem ser facilmente resolvidos em um computador cl\xe1ssico, e n\xe3o temos necessidade de um computador qu\xe2ntico para resolv\xea-los. Por outro lado, existem problemas muito dif\xedceis para os quais os computadores qu\xe2nticos s\xe3o necess\xe1rios para resolver. Um exemplo famoso \xe9 encontrar os fatores primos de inteiros enormes. A criptografia RSA depende da dificuldade desse problema, e o algoritmo de Shor foi projetado para resolv\xea-lo em um computador qu\xe2ntico. Outro exemplo \xe9 encontrar uma solu\xe7\xe3o em um conjunto de dados n\xe3o ordenado \u2014 isso pode teoricamente ser resolvido pelo algoritmo qu\xe2ntico conhecido como algoritmo de Grover. No entanto, a maioria dos especialistas concorda que esses tipos de algoritmos v\xe3o necessitar da implementa\xe7\xe3o de corre\xe7\xe3o de erros, e a tecnologia ainda n\xe3o chegou l\xe1."}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, estamos buscando problemas que possamos abordar em algum ponto intermedi\xe1rio entre os muito f\xe1ceis e os muito dif\xedceis \u2014 aqueles que os computadores qu\xe2nticos de hoje podem enfrentar, mas com os quais os computadores cl\xe1ssicos t\xeam dificuldade."}),"\n",(0,i.jsx)(a.h3,{id:"complexity-classes",children:"Classes de complexidade"}),"\n",(0,i.jsx)(a.p,{children:"A dificuldade desses problemas \xe9 categorizada e analisada em um ramo da ci\xeancia da computa\xe7\xe3o chamado teoria da complexidade computacional. Existem muitas classes de complexidade diferentes na computa\xe7\xe3o cl\xe1ssica, mas algumas das mais fundamentais s\xe3o:"}),"\n",(0,i.jsxs)(a.ul,{children:["\n",(0,i.jsx)(a.li,{children:"P: Problemas que podem ser resolvidos em tempo polinomial \xe0 medida que a escala do problema aumenta. S\xe3o f\xe1ceis de resolver."}),"\n",(0,i.jsx)(a.li,{children:'NP: Isso significa "polinomial n\xe3o determin\xedstico". Esses problemas n\xe3o necessariamente podem ser resolvidos em tempo polinomial, mas suas respostas podem ser verificadas em tempo polinomial.'}),"\n",(0,i.jsx)(a.li,{children:"NP-completo s\xe3o os problemas mais dif\xedceis em NP e n\xe3o t\xeam solu\xe7\xe3o polinomial conhecida. \xc9 aqui que vivem problemas famosos como o caixeiro-viajante e o jogo Sudoku."}),"\n",(0,i.jsx)(a.li,{children:"BPP, ou problemas polinomiais de erro limitado, que podem ser resolvidos dentro de um certo limiar de erro por um computador cl\xe1ssico probabil\xedstico em tempo polinomial."}),"\n"]}),"\n",(0,i.jsx)(a.p,{children:"Quando o conceito de computa\xe7\xe3o qu\xe2ntica foi inventado, as pessoas dedicaram esfor\xe7os consider\xe1veis tentando descobrir qual classe de problemas esses novos tipos de computadores poderiam resolver eficientemente. Uma nova classe de problemas foi inventada:"}),"\n",(0,i.jsxs)(a.ul,{children:["\n",(0,i.jsx)(a.li,{children:"BQP, ou problemas polinomiais qu\xe2nticos de erro limitado. Este \xe9 o equivalente qu\xe2ntico do BPP: \xe9 a classe de problemas de decis\xe3o que podem ser resolvidos por um computador qu\xe2ntico em tempo polinomial com uma pequena chance de erro."}),"\n"]}),"\n",(0,i.jsx)(a.p,{children:(0,i.jsx)(a.img,{alt:"Rela\xe7\xf5es suspeitas entre classes de complexidade",src:o(52600).A+"",width:"976",height:"682"})}),"\n",(0,i.jsx)(a.p,{children:"Todas essas classes vivem em uma classe maior que chamamos de PSPACE. Acima est\xe1 um diagrama das rela\xe7\xf5es suspeitas entre algumas das classes de complexidade, mas isso \xe9 muito dif\xedcil de provar definitivamente de forma matem\xe1tica. Voc\xea vai notar que BQP n\xe3o necessariamente se sobrep\xf5e com NP-completo. Mas voc\xea ainda pode ter visto algumas abordagens de computa\xe7\xe3o qu\xe2ntica que tentam resolver problemas em NP-completo."}),"\n",(0,i.jsx)(a.p,{children:"Um equ\xedvoco comum \xe9 que n\xe3o h\xe1 sentido em explorar solu\xe7\xf5es qu\xe2nticas para quaisquer problemas onde n\xe3o tenha sido encontrada uma prova matem\xe1tica de acelera\xe7\xe3o qu\xe2ntica. Mas uma prova matem\xe1tica de que um algoritmo qu\xe2ntico \xe9 mais r\xe1pido do que seu equivalente cl\xe1ssico \xe9 dif\xedcil de encontrar. O algoritmo de Shor e o de Grover s\xe3o dois dos poucos exemplos onde isso foi feito at\xe9 agora. Na verdade, provar rigorosamente que P e NP s\xe3o diferentes \xe9 uma das quest\xf5es abertas mais not\xf3rias de toda a matem\xe1tica, mesmo que toda a intui\xe7\xe3o nos diga que devem ser."}),"\n",(0,i.jsx)(a.p,{children:"Mas a forma como um algoritmo escala com o aumento do tamanho do problema \u2014 que \xe9 o que \xe9 refletido na classe de complexidade \u2014 nem sempre \xe9 a caracter\xedstica mais relevante de um algoritmo. Esse escalonamento geralmente representa o pior caso poss\xedvel. \xc9 bastante poss\xedvel que, na pr\xe1tica, o pior caso n\xe3o seja o que encontramos com mais frequ\xeancia."}),"\n",(0,i.jsx)(a.p,{children:"S\xf3 porque as provas de dificuldade s\xe3o complicadas n\xe3o significa que n\xe3o podemos progredir. Introduzimos a ideia de solu\xe7\xf5es heur\xedsticas. Se voc\xea \xe9 um experimentalista, provavelmente conhece e gosta desses tipos de solu\xe7\xf5es. Uma heur\xedstica \xe9 qualquer abordagem para resolver um problema que \xe9 pragm\xe1tica, mas n\xe3o necessariamente \xf3tima, pois as solu\xe7\xf5es n\xe3o precisam ser \xf3timas para serem \xfateis. Por exemplo, pense em aplica\xe7\xf5es financeiras. Ainda n\xe3o encontramos uma acelera\xe7\xe3o exponencial para a maioria dos algoritmos financeiros para os quais o qu\xe2ntico poderia ser usado, mas n\xe3o precisamos de uma solu\xe7\xe3o \xf3tima. Em finan\xe7as, at\xe9 mesmo uma solu\xe7\xe3o que seja apenas 0,1% mais eficiente poderia equivaler a bilh\xf5es de d\xf3lares de lucro."}),"\n",(0,i.jsx)(a.h3,{id:"todays-quantum-computers-and-their-limits",children:"Os computadores qu\xe2nticos de hoje e seus limites"}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, como sabemos quais casos de uso e problemas podem ser adequados para a computa\xe7\xe3o qu\xe2ntica agora? Existe uma boa raz\xe3o para acreditar que utilidade qu\xe2ntica, ou at\xe9 mesmo vantagem, pode ser encontrada agora ou em um futuro pr\xf3ximo?"}),"\n",(0,i.jsx)(a.p,{children:"Talvez seja mais f\xe1cil primeiro nomear as coisas que o problema certamente n\xe3o deve ter. Ele n\xe3o pode exigir um n\xfamero enorme de qubits. Ainda n\xe3o temos processadores com milhares a milh\xf5es de qubits dispon\xedveis. Essa \xe9 uma das principais raz\xf5es pelas quais o algoritmo de Shor e similares est\xe3o t\xe3o longe de serem realizados. Os circuitos tamb\xe9m n\xe3o podem ser muito profundos. O limite para a profundidade do circuito depende de muitos fatores, mas em geral, se seu experimento requer uma profundidade que voc\xea ainda n\xe3o viu na literatura, provavelmente n\xe3o vai funcionar. E, por \xfaltimo, qualquer tipo de algoritmo que saibamos que exigir\xe1 corre\xe7\xe3o de erros ainda n\xe3o pode ser feito."}),"\n",(0,i.jsxs)(a.p,{children:["Todas essas limita\xe7\xf5es s\xe3o abordadas no ",(0,i.jsx)(a.a,{href:"https://www.ibm.com/quantum/technology#roadmap",children:"roteiro do IBM Quantum\xae"})," e esperamos alcan\xe7ar a corre\xe7\xe3o de erros no in\xedcio dos anos 2030, mas por enquanto, precisamos buscar experimentos que fa\xe7am uso da maioria dos qubits atualmente dispon\xedveis em um determinado QPU. Tamb\xe9m enfatizamos a import\xe2ncia da mitiga\xe7\xe3o e supress\xe3o de erros. E, por \xfaltimo, deve haver uma extens\xe3o \xf3bvia para aplica\xe7\xf5es futuras que seriam importantes para a sociedade e que poder\xedamos ver eventualmente levando a uma vantagem qu\xe2ntica."]}),"\n",(0,i.jsx)(a.h2,{id:"application-areas-and-use-cases",children:"\xc1reas de aplica\xe7\xe3o e casos de uso"}),"\n",(0,i.jsx)(a.p,{children:"Agora vamos falar sobre alguns exemplos de casos de uso, que se enquadram em tr\xeas categorias principais que identificamos como mais prov\xe1veis de ter resultados favor\xe1veis no curto a m\xe9dio prazo:"}),"\n",(0,i.jsxs)(a.ol,{children:["\n",(0,i.jsxs)(a.li,{children:["\n",(0,i.jsxs)(a.p,{children:["Simula\xe7\xf5es da Natureza. Os m\xe9todos cl\xe1ssicos atuais de simula\xe7\xf5es at\xf4micas e moleculares s\xe3o limitados por descri\xe7\xf5es matem\xe1ticas ineficientes da estrutura at\xf4mica. Armazenar e manipular um estado qu\xe2ntico exige recursos exponencialmente maiores em um computador cl\xe1ssico, mas pode ser feito eficientemente em um computador qu\xe2ntico. Isso poderia levar a desenvolvimentos no sequestro de di\xf3xido de carbono, baterias alternativas ou na inven\xe7\xe3o de novos medicamentos. Alguns algoritmos especialmente relevantes nessa \xe1rea s\xe3o: o Variational Quantum Eigensolver (VQE), que \xe9 usado para estimar certas propriedades de um material, como estados de equil\xedbrio ou de energia m\xednima; o algoritmo de Simula\xe7\xe3o de Din\xe2mica Temporal (TDS), que \xe9 usado para estimar fun\xe7\xf5es de resposta ou propriedades espectrais de materiais; e um rec\xe9m-chegado, ",(0,i.jsx)(a.a,{href:"/learning/courses/quantum-diagonalization-algorithms/sqd-overview",children:"Diagonaliza\xe7\xe3o Qu\xe2ntica Baseada em Amostras (SQD)"}),", que achamos que vamos ouvir muito mais nos pr\xf3ximos tempos."]}),"\n"]}),"\n",(0,i.jsxs)(a.li,{children:["\n",(0,i.jsx)(a.p,{children:"Otimiza\xe7\xe3o. Esta \xe1rea \xe9 onipresente na computa\xe7\xe3o, portanto os casos de uso s\xe3o numerosos e variados. Alguns exemplos que ouvimos bastante s\xe3o otimiza\xe7\xe3o de portf\xf3lio em finan\xe7as, design industrial e distribui\xe7\xe3o e cadeia de suprimentos. O algoritmo mais comum que voc\xea provavelmente vai ouvir relacionado a finan\xe7as \xe9 o que j\xe1 cobrimos com alguma profundidade: o algoritmo de otimiza\xe7\xe3o aproximada qu\xe2ntica, ou QAOA."}),"\n"]}),"\n",(0,i.jsxs)(a.li,{children:["\n",(0,i.jsx)(a.p,{children:"Aprendizado de m\xe1quina qu\xe2ntico. Esta \xe1rea gerou muita empolga\xe7\xe3o nos \xfaltimos anos, mas \xe9 prov\xe1vel que o QML n\xe3o seja \xfatil t\xe3o cedo quanto a simula\xe7\xe3o. Mas existem, no entanto, alguns algoritmos impressionantes que est\xe3o sendo desenvolvidos para abordar alguns casos de uso muito importantes. Alguns desses casos de uso poss\xedveis s\xe3o processamento de linguagem natural, an\xe1lise de tr\xe1fego de rede e at\xe9 detec\xe7\xe3o de fraudes em transa\xe7\xf5es financeiras. Algoritmos relevantes nesta \xe1rea s\xe3o a m\xe1quina de vetores de suporte qu\xe2ntica (QSVM), redes neurais qu\xe2nticas (QNN) e redes adversariais generativas qu\xe2nticas."}),"\n"]}),"\n"]}),"\n",(0,i.jsx)(a.p,{children:"Dentro dessas amplas \xe1reas de aplica\xe7\xe3o, a comunidade v\xea benef\xedcios em grupos que trabalham juntos e est\xe3o focados em um t\xf3pico mais espec\xedfico. A IBM\xae liderou uma iniciativa chamada Grupos de Trabalho para tentar ajudar colaboradores a se conhecerem e criar sinergia produtiva em quatro \xe1reas espec\xedficas: sa\xfade e ci\xeancias da vida, materiais e computa\xe7\xe3o de alto desempenho (HPC), f\xedsica de altas energias e otimiza\xe7\xe3o. E recentemente, um quinto grupo de trabalho sobre sustentabilidade foi criado."}),"\n",(0,i.jsx)(a.p,{children:"Agora vamos nos aprofundar em alguns problemas que foram recentemente abordados por alguns desses grupos de trabalho. O principal objetivo aqui n\xe3o \xe9 entender cada detalhe de um experimento \u2014 isso pode ser intimidador at\xe9 mesmo para especialistas se o artigo estiver um pouco fora de sua \xe1rea de especialidade. O objetivo \xe9 simplesmente ajudar a desenvolver uma intui\xe7\xe3o para os tipos de problemas para os quais os computadores qu\xe2nticos s\xe3o adequados e como abordamos sua solu\xe7\xe3o. E se voc\xea estiver interessado, encorajamos voc\xea a ler os artigos completos."}),"\n",(0,i.jsx)(a.h3,{id:"use-case-1-simulating-hadron-dynamics",children:"Caso de Uso 1: Simulando a din\xe2mica de h\xe1drons"}),"\n",(0,i.jsxs)(a.p,{children:["Primeiro, vamos nos aprofundar em um artigo do grupo de Martin Savage na Universidade de Washington chamado ",(0,i.jsx)(a.a,{href:"https://journals.aps.org/prd/abstract/10.1103/PhysRevD.109.114510",children:"Quantum Simulations of Hadron Dynamics in the Schwinger Model Using 112 Qubits"}),"."]}),"\n",(0,i.jsx)(a.p,{children:'Se voc\xea n\xe3o \xe9 um f\xedsico de altas energias, ainda pode estar familiarizado com o termo "h\xe1dron", como no Grande Colisor de H\xe1drons (LHC), que \xe9 o gigantesco acelerador de part\xedculas, com 27 km de circunfer\xeancia, que tornou poss\xedvel finalmente observar o b\xf3son de Higgs. Um h\xe1dron \xe9 uma part\xedcula subat\xf4mica composta formada por outras pequenas part\xedculas chamadas quarks. Alguns exemplos de h\xe1drons s\xe3o n\xeautrons e pr\xf3tons.'}),"\n",(0,i.jsx)(a.p,{children:"Para dar um pouco de contexto, o LHC foi constru\xeddo para permitir o estudo da f\xedsica fundamental colindo part\xedculas em energias super altas. Com o LHC, os cientistas esperam aprender mais sobre o universo primitivo e as leis fundamentais da natureza. Em princ\xedpio, as intera\xe7\xf5es dessas part\xedculas poderiam ser simuladas do in\xedcio ao fim com um computador qu\xe2ntico suficientemente poderoso. Ainda n\xe3o chegamos l\xe1, mas estamos progredindo."}),"\n",(0,i.jsx)(a.p,{children:"O modelo de Schwinger \xe9 um modelo simples e popular usado para simular algumas dessas din\xe2micas. \xc9 um modelo que descreve o comportamento de el\xe9trons e p\xf3sitrons interagindo via f\xf3tons em 1+1D, ou seja, no tempo e em uma dimens\xe3o espacial. O modelo tem muitas semelhan\xe7as com a cromodin\xe2mica qu\xe2ntica (QCD), que descreve como quarks e h\xe1drons interagem, mas a QCD \xe9 extremamente dif\xedcil de simular. Portanto, o modelo de Schwinger \xe9 frequentemente usado como um modelo simplificado para investigar alguns fen\xf4menos comuns a ambos."}),"\n",(0,i.jsx)(a.p,{children:"Para entender por que abordaram esse problema, vamos nos fazer uma s\xe9rie de perguntas."}),"\n",(0,i.jsx)(a.p,{children:"Primeiro, por que eles tinham raz\xe3o para acreditar que simular isso em um computador qu\xe2ntico funcionaria? Nesse caso, os el\xe9trons e p\xf3sitrons no modelo de Schwinger t\xeam um efeito de blindagem, fazendo com que as correla\xe7\xf5es entre f\xe9rmions distantes decaiam exponencialmente com a separa\xe7\xe3o. Isso significa que n\xe3o h\xe1 tantas intera\xe7\xf5es de longa dist\xe2ncia necess\xe1rias de um qubit em um lado do chip para outro, o que sabemos ser muito propenso a erros. Portanto, isso \xe9 \xf3timo para o hardware dispon\xedvel hoje."}),"\n",(0,i.jsx)(a.p,{children:"Em seguida, por que esse t\xf3pico \xe9 de interesse? A f\xedsica de altas energias em geral \xe9 de grande interesse. As pessoas estavam dispostas a gastar bilh\xf5es de d\xf3lares para construir o LHC, e muitos milhares de cientistas e t\xe9cnicos em todo o mundo dedicaram suas carreiras a esse campo. Embora o modelo de Schwinger seja simplista e n\xe3o seja projetado para cobrir tr\xeas dimens\xf5es espaciais, ainda \xe9 uma simplifica\xe7\xe3o \xfatil da teoria completa."}),"\n",(0,i.jsx)(a.p,{children:"Por fim, como esse trabalho foi feito, ou como abordar\xedamos o problema se estiv\xe9ssemos buscando continuar esse trabalho? Em experimentos do tipo simula\xe7\xe3o, o VQE \xe9 uma das abordagens mais comuns, e o primeiro passo \xe9 quase sempre o mesmo: preparar o estado fundamental. Neste caso, \xe9 um estado de v\xe1cuo. Neste experimento, eles usam uma nova vers\xe3o do VQE chamada SC-ADAPT-VQE (que significa Scalable Circuits - Adaptive Derivative-Assembled Pseudo-Trotter ansatz-VQE) para preparar tanto o estado fundamental quanto o pacote de onda de h\xe1drons nesse v\xe1cuo. O pr\xf3ximo passo \xe9 deixar os h\xe1drons evolu\xedrem no tempo. Por fim, identificar os observ\xe1veis que voc\xea deseja medir e medi-los."}),"\n",(0,i.jsx)(a.p,{children:"Se esses passos parecerem um pouco familiares, tirando a parte do pacote de onda de h\xe1drons, \xe9 porque esses passos s\xe3o muito semelhantes ao que cobrimos no exemplo do QAOA na aula anterior. Come\xe7amos em um estado familiar (aqui o estado de v\xe1cuo) e, em seguida, deixamos evoluir no tempo com uma s\xe9rie de Hamiltonianos exponenciados. Muitos algoritmos variacionais seguem essa abordagem geral. Uma grande diferen\xe7a aqui, no entanto, \xe9 que criamos o pacote de onda de h\xe1drons centrado no nosso circuito, antes de come\xe7armos a deix\xe1-lo evoluir."}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, como criamos o pacote de onda? No v\xe1cuo, um h\xe1dron pode ser excitado criando um par f\xe9rmion-antif\xe9rmion em s\xedtios adjacentes. Ao preparar uma superposi\xe7\xe3o de tais h\xe1drons em locais diferentes, um pacote de onda arbitr\xe1rio pode ser preparado. Os autores centraram seu pacote de onda no meio do circuito para observar a evolu\xe7\xe3o sem atingir um limite."}),"\n",(0,i.jsx)(a.p,{children:"Mas lembre-se: o nome do jogo ao trabalhar com QPUs ruidosos \xe9 manter a profundidade do circuito gerenci\xe1vel. Para fazer isso, o protocolo SC-ADAPT-VQE usa simetrias e hierarquias em escalas de comprimento para determinar circuitos qu\xe2nticos de baixa profundidade para a prepara\xe7\xe3o de estados. Isso criar\xe1 um ansatz com um n\xfamero menor de par\xe2metros e, portanto, uma profundidade mais rasa."}),"\n",(0,i.jsx)(a.p,{children:"O experimento foi realizado em um dispositivo IBM Quantum Heron e incluiu alguns tipos diferentes de mitiga\xe7\xe3o e supress\xe3o de erros: desacoplamento din\xe2mico, extrapola\xe7\xe3o de ru\xeddo zero, twirling de Pauli e uma t\xe9cnica desenvolvida recentemente chamada renormaliza\xe7\xe3o de decoer\xeancia de operadores."}),"\n",(0,i.jsx)(a.p,{children:(0,i.jsx)(a.img,{alt:"Resultados das simula\xe7\xf5es de h\xe1drons",src:o(77894).A+"",width:"1158",height:"838"})}),"\n",(0,i.jsx)(a.p,{children:"Acima est\xe1 uma figura do artigo mostrando o observ\xe1vel de interesse, o condensado quiral, que \xe9 basicamente uma fase superfluida dos h\xe1drons. Agora podemos ver o pacote de onda no centro dos s\xedtios que foram designados para executar esse experimento. As linhas pretas s\xe3o os resultados sem erros da simula\xe7\xe3o cl\xe1ssica (computacionalmente cara), enquanto os pontos com barras de erro s\xe3o os resultados do computador qu\xe2ntico IBM de 133 qubits, Torino."}),"\n",(0,i.jsxs)(a.p,{children:["Vemos dois passos temporais diferentes na evolu\xe7\xe3o do pacote de onda. No tempo ",(0,i.jsxs)(a.span,{className:"katex",children:[(0,i.jsx)(a.span,{className:"katex-mathml",children:(0,i.jsx)(a.math,{xmlns:"http://www.w3.org/1998/Math/MathML",children:(0,i.jsxs)(a.semantics,{children:[(0,i.jsxs)(a.mrow,{children:[(0,i.jsx)(a.mi,{children:"t"}),(0,i.jsx)(a.mo,{children:"="}),(0,i.jsx)(a.mn,{children:"1"})]}),(0,i.jsx)(a.annotation,{encoding:"application/x-tex",children:"t=1"})]})})}),(0,i.jsxs)(a.span,{className:"katex-html","aria-hidden":"true",children:[(0,i.jsxs)(a.span,{className:"base",children:[(0,i.jsx)(a.span,{className:"strut",style:{height:"0.6151em"}}),(0,i.jsx)(a.span,{className:"mord mathnormal",children:"t"}),(0,i.jsx)(a.span,{className:"mspace",style:{marginRight:"0.2778em"}}),(0,i.jsx)(a.span,{className:"mrel",children:"="}),(0,i.jsx)(a.span,{className:"mspace",style:{marginRight:"0.2778em"}})]}),(0,i.jsxs)(a.span,{className:"base",children:[(0,i.jsx)(a.span,{className:"strut",style:{height:"0.6444em"}}),(0,i.jsx)(a.span,{className:"mord",children:"1"})]})]})]}),", voc\xea pode ver que o condensado quiral \xe9 estreito e localizado, e tamb\xe9m corresponde bem \xe0 simula\xe7\xe3o cl\xe1ssica. Em ",(0,i.jsxs)(a.span,{className:"katex",children:[(0,i.jsx)(a.span,{className:"katex-mathml",children:(0,i.jsx)(a.math,{xmlns:"http://www.w3.org/1998/Math/MathML",children:(0,i.jsxs)(a.semantics,{children:[(0,i.jsxs)(a.mrow,{children:[(0,i.jsx)(a.mi,{children:"t"}),(0,i.jsx)(a.mo,{children:"="}),(0,i.jsx)(a.mn,{children:"14"})]}),(0,i.jsx)(a.annotation,{encoding:"application/x-tex",children:"t=14"})]})})}),(0,i.jsxs)(a.span,{className:"katex-html","aria-hidden":"true",children:[(0,i.jsxs)(a.span,{className:"base",children:[(0,i.jsx)(a.span,{className:"strut",style:{height:"0.6151em"}}),(0,i.jsx)(a.span,{className:"mord mathnormal",children:"t"}),(0,i.jsx)(a.span,{className:"mspace",style:{marginRight:"0.2778em"}}),(0,i.jsx)(a.span,{className:"mrel",children:"="}),(0,i.jsx)(a.span,{className:"mspace",style:{marginRight:"0.2778em"}})]}),(0,i.jsxs)(a.span,{className:"base",children:[(0,i.jsx)(a.span,{className:"strut",style:{height:"0.6444em"}}),(0,i.jsx)(a.span,{className:"mord",children:"14"})]})]})]}),", est\xe1 muito mais espalhado. A compara\xe7\xe3o com o simulador n\xe3o \xe9 t\xe3o perfeita agora, mas voc\xea ainda pode ver um acordo muito bom entre a teoria e os dados, o que \xe9 encorajador."]}),"\n",(0,i.jsx)(a.p,{children:"Em conclus\xe3o, este \xe9 um exemplo muito legal do tipo de trabalho de simula\xe7\xe3o ao qual voc\xea pode n\xe3o pensar inicialmente em aplicar a computa\xe7\xe3o qu\xe2ntica, mas que mostra grande promessa. N\xe3o \xe9 perfeito, mas voc\xea n\xe3o precisa ser um especialista em f\xedsica de part\xedculas para ver que o computador qu\xe2ntico prev\xea com precis\xe3o a propaga\xe7\xe3o para fora do pacote de onda, que \xe9 exatamente o que esperar\xedamos encontrar. Esperamos que trabalhos futuros nessa \xe1rea continuem e que os f\xedsicos de altas energias continuem encontrando formas de incorporar a computa\xe7\xe3o qu\xe2ntica em seus fluxos de trabalho. O objetivo \xe9 resolver problemas te\xf3ricos dif\xedceis com mais precis\xe3o e usar experimentos para aceitar ou rejeitar teorias, na esperan\xe7a de descobrir nova f\xedsica, construir detectores melhorados e chegar a uma melhor compreens\xe3o da natureza em seu n\xedvel mais fundamental."}),"\n",(0,i.jsx)(a.h3,{id:"use-case-2-optimization-of-an-ising-spin-glass",children:"Caso de Uso 2: Otimiza\xe7\xe3o de um vidro de spin de Ising"}),"\n",(0,i.jsxs)(a.p,{children:["Nosso pr\xf3ximo exemplo foca em otimiza\xe7\xe3o e ser\xe1 um mergulho profundo em um artigo chamado ",(0,i.jsx)(a.a,{href:"https://arxiv.org/abs/2405.13898",children:"Bias-Field Digitized Counterdiabatic Quantum Optimization"}),", realizado por membros da equipe Kipu Quantum e da Universidade do Pa\xeds Basco, na Espanha."]}),"\n",(0,i.jsx)(a.p,{children:'No artigo, os autores desenvolveram um novo m\xe9todo de otimiza\xe7\xe3o e o aplicaram para encontrar o estado fundamental de um vidro de spin de Ising. Como discutimos anteriormente, muitos problemas de otimiza\xe7\xe3o combinat\xf3ria podem ser reformulados como a busca por estados de baixa energia de Hamiltonianos de Ising. O modelo de Ising descreve a intera\xe7\xe3o de uma matriz de spins microsc\xf3picos. Em alguns regimes, o modelo prev\xea que os spins se comportam como um vidro, no qual os momentos magn\xe9ticos est\xe3o desordenados acima de uma chamada "temperatura de congelamento."'}),"\n",(0,i.jsx)(a.p,{children:"Come\xe7aremos como fizemos antes, com uma s\xe9rie de defini\xe7\xf5es. A primeira \xe9 contraadiab\xe1tico, que \xe9 um tipo de evolu\xe7\xe3o que suprime efeitos n\xe3o adiab\xe1ticos experimentados por um sistema, independentemente da velocidade com que esses processos ocorrem. Lembre-se do teorema adiab\xe1tico do \xfaltimo epis\xf3dio \u2014 geralmente voc\xea precisa evoluir um sistema muito lentamente se quiser que ele permane\xe7a no estado fundamental. Isso \xe9 um grande problema porque quanto mais lentamente precisamos evoluir as coisas, mais tempo temos para que ocorram erros. A condu\xe7\xe3o contraadiab\xe1tica (CD) visa combater isso adicionando termos que contrabalanciam essas excita\xe7\xf5es indesejadas. A ideia principal aqui \xe9 acelerar todo o experimento e reduzir a profundidade do circuito qu\xe2ntico suprimindo excita\xe7\xf5es que poderiam causar transi\xe7\xf5es esp\xfarias."}),"\n",(0,i.jsx)(a.p,{children:"Agora para o outro jarg\xe3o no t\xedtulo: o campo de vi\xe9s. Outros algoritmos iterativos, como o VQE, inserem par\xe2metros cl\xe1ssicos nos estados e usam otimizadores cl\xe1ssicos para pesquisar o espa\xe7o de par\xe2metros multidimensional para o conjunto de par\xe2metros que produz um valor de expectativa m\xednimo para um Hamiltoniano fixo. Neste caso, eles variam o Hamiltoniano a cada vez, movendo-se adiabaticamente de um caso conhecido para o caso de interesse. Para mudar o Hamiltoniano, eles simplesmente aplicam diretamente o valor de expectativa de Pauli-Z de uma itera\xe7\xe3o como um campo de vi\xe9s no Hamiltoniano para a pr\xf3xima itera\xe7\xe3o. Dessa forma, eles direcionam a din\xe2mica em dire\xe7\xe3o \xe0 solu\xe7\xe3o real sem a necessidade de otimizadores cl\xe1ssicos."}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, por que esse experimento \xe9 de interesse? Os vidros de spin de Ising s\xe3o de interesse fundamental na f\xedsica, mas essa nova abordagem \xe9 ainda mais geral do que isso. Ela poderia ser aplicada a muitos problemas de otimiza\xe7\xe3o, ent\xe3o o artigo \xe9 de amplo interesse."}),"\n",(0,i.jsx)(a.p,{children:"E por que ach\xe1vamos que isso funcionaria? O algoritmo que eles est\xe3o propondo acelera a evolu\xe7\xe3o para reduzir a profundidade do circuito, ao mesmo tempo em que suprime transi\xe7\xf5es n\xe3o adiab\xe1ticas. Al\xe9m disso, n\xe3o depende de nenhuma sub-rotina de otimiza\xe7\xe3o cl\xe1ssica, o que pode ser um problema levando a plat\xf4s est\xe9reis e ficando preso em m\xednimos locais. Por \xfaltimo, os autores tamb\xe9m se certificam de alinhar as intera\xe7\xf5es no Hamiltoniano do problema com a conectividade do hardware nos QPUs reais, o que \xe9 sempre muito importante."}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, como esse m\xe9todo funciona? Mais uma vez, ele n\xe3o usa otimizadores cl\xe1ssicos, ao contr\xe1rio da maioria dos outros algoritmos qu\xe2nticos iterativos. Em vez disso, ao alimentar a solu\xe7\xe3o de cada itera\xe7\xe3o como entrada para a pr\xf3xima, o algoritmo de otimiza\xe7\xe3o qu\xe2ntica digitalizada com campo de vi\xe9s refina incrementalmente o estado fundamental, aproximando-o cada vez mais do estado final evolu\xeddo. E combinado com os protocolos contraadiab\xe1ticos, podemos fazer isso mesmo com circuitos qu\xe2nticos de profundidade curta que devem rodar sem problemas em hardware ruidoso."}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, quando o experimento foi realizado, os autores escolheram executar o algoritmo no computador qu\xe2ntico IBM Quantum Brisbane de 127 qubits. Abaixo est\xe1 uma figura mostrando a 8\xaa itera\xe7\xe3o do algoritmo de otimiza\xe7\xe3o para uma inst\xe2ncia de vidro de spin de vizinhos mais pr\xf3ximos gerada aleatoriamente em 100 qubits. Eles comparam resultados idealizados de simula\xe7\xe3o cl\xe1ssica de DCQO e BF-DCQO, bem como o resultado experimental executado no computador qu\xe2ntico. Eles tamb\xe9m mostram o resultado de um solver cl\xe1ssico chamado Gurobi como refer\xeancia. Com apenas 10 itera\xe7\xf5es, o BF-DCQO fornece uma melhora dr\xe1stica em compara\xe7\xe3o com o DCQO. Embora o resultado experimental seja um pouco diferente do resultado ideal devido ao ru\xeddo, o desempenho ainda \xe9 melhor do que o DCQO ideal. Isso mostra que ainda h\xe1 muito progresso excelente sendo feito em rela\xe7\xe3o \xe0 otimiza\xe7\xe3o qu\xe2ntica e bons resultados est\xe3o sendo reportados em mais de 100 qubits pela primeira vez."}),"\n",(0,i.jsx)(a.p,{children:(0,i.jsx)(a.img,{alt:"Resultados do artigo do vidro de spin de Ising",src:o(43410).A+"",width:"976",height:"682"})}),"\n",(0,i.jsx)(a.h3,{id:"use-case-3-mrna-secondary-structure-prediction",children:"Caso de Uso 3: Previs\xe3o de estrutura secund\xe1ria de mRNA"}),"\n",(0,i.jsxs)(a.p,{children:["Por fim, vamos discutir um artigo da Moderna Pharmaceuticals chamado ",(0,i.jsx)(a.a,{href:"https://arxiv.org/abs/2405.20328",children:"mRNA Secondary Structure Prediction Using Utility-Scale Quantum Computers"}),"."]}),"\n",(0,i.jsx)(a.p,{children:"Primeiro, uma breve revis\xe3o sobre mRNA. O RNA mensageiro \xe9 um tipo de RNA envolvido na s\xedntese de prote\xednas. Ele basicamente l\xea as instru\xe7\xf5es fornecidas pelo DNA. A estrutura secund\xe1ria do mRNA \xe9 como a cadeia est\xe1 dobrada, como mostrado no diagrama abaixo. E o problema de previs\xe3o de estrutura secund\xe1ria de RNA \xe9 o problema de encontrar o dobramento mais est\xe1vel da sequ\xeancia de bases ou nucleot\xeddeos que comp\xf5em o RNA: adenina (A), citosina (C), uracila (U) e guanina (G). A imagem abaixo mostra algumas estruturas de dobramento comuns encontradas no mRNA, cada cor representa um tipo diferente de estrutura secund\xe1ria. O que torna uma estrutura mais favor\xe1vel do que as outras n\xe3o \xe9 bem compreendido; tudo que podemos fazer \xe9 calcular qual estrutura produz a menor energia livre em compara\xe7\xe3o com o estado n\xe3o dobrado. E \xe9 a\xed que os computadores qu\xe2nticos entram."}),"\n",(0,i.jsx)(a.p,{children:(0,i.jsx)(a.img,{alt:"Diagrama de estrutura secund\xe1ria de mRNA",src:o(41923).A+"",width:"638",height:"842"})}),"\n",(0,i.jsx)(a.p,{children:"Ent\xe3o, por que as estruturas secund\xe1rias de mRNA s\xe3o importantes? A previs\xe3o precisa delas \xe9 crucial n\xe3o s\xf3 para entender o DNA e nossos genes, mas tamb\xe9m para projetar terap\xeauticas baseadas em RNA, como a vacina contra a COVID-19."}),"\n",(0,i.jsx)(a.p,{children:"H\xe1 muito tempo se sabe que esse \xe9 um problema de otimiza\xe7\xe3o formid\xe1vel para computadores cl\xe1ssicos devido ao enorme n\xfamero de configura\xe7\xf5es poss\xedveis. Para algumas configura\xe7\xf5es, sabe-se que \xe9 um problema NP-completo. No entanto, em um computador qu\xe2ntico, podemos formular a previs\xe3o de estrutura secund\xe1ria como um problema de otimiza\xe7\xe3o bin\xe1ria \u2014 algo que sabemos como lidar. Al\xe9m disso, j\xe1 havia evid\xeancias na literatura de previs\xf5es precisas de RNA em dispositivos qu\xe2nticos de pequena escala e simuladores qu\xe2nticos. Mas isso funcionaria em hardware maior?"}),"\n",(0,i.jsx)(a.p,{children:"Este experimento foi realizado usando algo chamado eigensolver qu\xe2ntico variacional de valor em risco condicional, que \xe9 uma modifica\xe7\xe3o de um algoritmo VQE tradicional e espera-se que alcance uma melhor converg\xeancia."}),"\n",(0,i.jsx)(a.p,{children:(0,i.jsx)(a.img,{alt:"Resultados do artigo de mRNA",src:o(65188).A+"",width:"1158",height:"686"})}),"\n",(0,i.jsx)(a.p,{children:"O gr\xe1fico acima mostra a distribui\xe7\xe3o das probabilidades de medi\xe7\xe3o das bitstrings amostradas, com as energias correspondentes para uma inst\xe2ncia de 42 nucleot\xeddeos e 80 qubits. Aqui, as bitstrings simbolizam emparelhamentos de nucleot\xeddeos. Ele ilustra que a bitstring de menor energia encontrada pelo computador qu\xe2ntico corresponde \xe0quela do solver cl\xe1ssico comparativo, o que \xe9 \xf3timo. Tamb\xe9m \xe9 mostrada a estrutura dobrada ideal dessa cadeia de nucleot\xeddeos com base na bitstring de menor energia que o computador qu\xe2ntico encontrou."}),"\n",(0,i.jsx)(a.h2,{id:"conclusion",children:"Conclus\xe3o"}),"\n",(0,i.jsx)(a.p,{children:"Esperamos que esses tr\xeas casos de uso tenham lhe dado contexto suficiente para entender como \xe9 o trabalho de ponta na \xe1rea agora, e a confian\xe7a para tentar novos experimentos qu\xe2nticos que voc\xea pode n\xe3o ter tentado antes."}),"\n",(0,i.jsx)(a.p,{children:"Lembre-se: a computa\xe7\xe3o qu\xe2ntica n\xe3o \xe9 boa para todo problema. E isso \xe9 apenas uma prova de como ficamos bons na computa\xe7\xe3o cl\xe1ssica. S\xf3 porque voc\xea acha que poderia aplicar a computa\xe7\xe3o qu\xe2ntica a um problema n\xe3o significa que vai produzir resultados interessantes; voc\xea deve considerar o escalonamento."}),"\n",(0,i.jsx)(a.p,{children:"A profundidade do circuito \xe9 uma faca de dois gumes. Precisamos que seja consideravelmente grande para fazer trabalho interessante que os computadores cl\xe1ssicos n\xe3o podem fazer, mas agora n\xe3o podemos aumentar a profundidade demais porque o ru\xeddo do hardware vai fazer a fidelidade diminuir. Tudo se resume a encontrar esse ponto ideal e saber que \xe9 um alvo em movimento. Ent\xe3o, reserve um tempo entre agora e a pr\xf3xima aula para pensar em um problema que voc\xea encontrou em sua pesquisa e como poderia abord\xe1-lo com o que aprendemos at\xe9 agora. E hey, sua solu\xe7\xe3o pode n\xe3o funcionar, e tudo bem. \xc9 por isso que isso \xe9 pesquisa."})]})}function u(e={}){const{wrapper:a}={...(0,r.R)(),...e.components};return a?(0,i.jsx)(a,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},52600(e,a,o){o.d(a,{A:()=>s});const s=o.p+"assets/images/complexity_classes-52979b588e98706373f7abc9b3f5f57c.avif"},77894(e,a,o){o.d(a,{A:()=>s});const s=o.p+"assets/images/hadron_paper-bc9c0a13fc3cd0e44b5c193902ce6dba.avif"},65188(e,a,o){o.d(a,{A:()=>s});const s=o.p+"assets/images/mrna_paper-4b1d694275f2539f69c49bfbb9b5ddd8.avif"},41923(e,a,o){o.d(a,{A:()=>s});const s=o.p+"assets/images/mrna_structure-962f2d5dfb98ac0a2e9c680e23d97ada.avif"},43410(e,a,o){o.d(a,{A:()=>s});const s=o.p+"assets/images/paper_results-aace6d8c4b97868e6cba7fc772e13ad9.avif"},28453(e,a,o){o.d(a,{R:()=>n,x:()=>m});var s=o(96540);const i={},r=s.createContext(i);function n(e){const a=s.useContext(r);return s.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function m(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:n(e.components),s.createElement(r.Provider,{value:a},e.children)}}}]);